class SecureTokenStore:
    """Store and validate API tokens using hashed values only."""
    
    def __init__(self):
        self._token_hashes = {}
        self._load_token_hashes()
    
    def _hash_token(self, token: str) -> str:
        """Hash a token using SHA-256 with a salt."""
        salt = os.environ.get('TOKEN_SALT', '')
        if not salt:
            logger.warning("TOKEN_SALT not set in environment")
        return hashlib.sha256(f"{salt}{token}".encode()).hexdigest()
    
    def _load_token_hashes(self):
        """Load pre-hashed tokens from secure storage."""
        if os.path.exists(API_TOKENS_HASH_FILE):
            with open(API_TOKENS_HASH_FILE, 'r') as f:
                for line in f:
                    line = line.strip()
                    if line and ':' in line:
                        role, token_hash = line.split(':', 1)
                        self._token_hashes[token_hash] = role.strip()
    
    def validate_token(self, token: str) -> tuple:
        """Validate a token and return (is_valid, role)."""
        if not token or not isinstance(token, str):
            return False, None
        token_hash = self._hash_token(token)
        if token_hash in self._token_hashes:
            return True, self._token_hashes[token_hash]
        return False, None
    
    def generate_token(self, role: str) -> str:
        """Generate a new secure token and store its hash."""
        token = secrets.token_urlsafe(32)
        token_hash = self._hash_token(token)
        self._token_hashes[token_hash] = role
        # Append hash to file
        with open(API_TOKENS_HASH_FILE, 'a') as f:
            f.write(f"{role}:{token_hash}\n")
        return token  # Return once to admin, never stored in plaintext


token_store = SecureTokenStore()


class RateLimiter:
    """Simple in-memory rate limiter."""
    
    def __init__(self, max_requests: int, window_seconds: int = 60):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self._requests = defaultdict(list)
    
    def is_allowed(self, client_id: str) -> bool:
        now = time.time()
        # Clean old entries
        self._requests[client_id] = [
            t for t in self._requests[client_id]
            if now - t < self.window_seconds
        ]
        if len(self._requests[client_id]) >= self.max_requests:
            return False
        self._requests[client_id].append(now)
        return True


rate_limiter = RateLimiter(MAX_REQUESTS_PER_MINUTE)


class FacialRecognitionModel:
    """
    Facial recognition model wrapper.
    
    Uses a simple eigenface-like approach for demonstration.
    In production, use a well-vetted library like face_recognition or dlib.
    
    SECURITY: This model is designed to NOT expose full probability distributions
    to prevent model inversion attacks.
    """
    
    def __init__(self):
        self.is_trained = False
        self.employee_ids = []
        self.mean_face = None
        self.eigenfaces = None
        self.projections = None  # Training projections
        self.image_size = (128, 128)
        self._training_labels = []
    
    def _preprocess_image(self, image: Image.Image) -> np.ndarray:
        """Securely preprocess an image."""
        # Convert to grayscale and resize
        img = image.convert('L').resize(self.image_size, Image.LANCZOS)
        arr = np.array(img, dtype=np.float64)
        # Normalize
        arr = arr.flatten()
        norm = np.linalg.norm(arr)
        if norm > 0:
            arr = arr / norm
        return arr
    
    def train(self, training_data: dict):
        """
        Train the model on employee photos.
        
        Args:
            training_data: dict mapping employee_id -> list of PIL Images
        """
        all_images = []
        labels = []
        employee_ids = []
        
        for emp_id, images in training_data.items():
            if not isinstance(emp_id, str) or len(emp_id) > 100:
                logger.warning("Skipping invalid employee ID during training")
                continue
            # Sanitize employee ID - allowlist alphanumeric and limited chars
            sanitized_id = ''.join(c for c in emp_id if c.isalnum() or c in '-_')
            if sanitized_id != emp_id:
                logger.warning("Employee ID was sanitized during training")
            
            employee_ids.append(sanitized_id)
            for img in images:
                processed = self._preprocess_image(img)
                all_images.append(processed)
                labels.append(len(employee_ids) - 1)
        
        if len(all_images) < 2:
            raise ValueError("Need at least 2 training images")
        
        self.employee_ids = employee_ids
        self._training_labels = labels
        
        # Compute mean face
        data_matrix = np.array(all_images)
        self.mean_face = np.mean(data_matrix, axis=0)
        
        # Center the data
        centered = data_matrix - self.mean_face
        
        # PCA via SVD (eigenfaces)
        n_components = min(50, len(all_images) - 1, centered.shape[1])
        
        # Use covariance trick for efficiency
        cov = centered @ centered.T
        eigenvalues, eigenvectors = np.linalg.eigh(cov)
        
        # Sort by eigenvalue descending
        idx = np.argsort(eigenvalues)[::-1][:n_components]
        eigenvectors = eigenvectors[:, idx]
        
        # Project back to image space
        self.eigenfaces = (centered.T @ eigenvectors).T
        # Normalize eigenfaces
        for i in range(len(self.eigenfaces)):
            norm = np.linalg.norm(self.eigenfaces[i])
            if norm > 0:
                self.eigenfaces[i] /= norm
        
        # Project training data
        self.projections = centered @ self.eigenfaces.T
        
        self.is_trained = True
        logger.info(f"Model trained with {len(employee_ids)} employees, {len(all_images)} images")
    
    def _predict_internal(self, image: Image.Image) -> list:
        """
        Internal prediction - returns distances to all classes.
        This is PRIVATE and should never be exposed via API.
        """
        if not self.is_trained:
            raise RuntimeError("Model not trained")
        
        processed = self._preprocess_image(image)
        centered = processed - self.mean_face
        projection = centered @ self.eigenfaces.T
        
        # Compute distance to each training sample
        distances = np.linalg.norm(self.projections - projection, axis=1)
        
        # Aggregate by employee (minimum distance per employee)
        employee_distances = {}
        for i, label in enumerate(self._training_labels):
            emp_id = self.employee_ids[label]
            if emp_id not in employee_distances or distances[i] < employee_distances[emp_id]:
                employee_distances[emp_id] = distances[i]
        
        return employee_distances
    
    def predict_secure(self, image: Image.Image) -> dict:
        """
        Secure prediction that returns ONLY the top match if above threshold.
        
        SECURITY: Does NOT return full probability distribution to prevent
        model inversion attacks. Only returns:
        - Whether a match was found
        - The top match employee ID (if confidence >= threshold)
        - A binary confidence level (high/medium) rather than exact scores
        
        This prevents attackers from iteratively querying the API to
        reconstruct training data or enumerate employees.
        """
        employee_distances = self._predict_internal(image)
        
        if not employee_distances:
            return {
                "match_found": False,
                "message": "No employees in database"
            }
        
        # Find best match
        best_emp = min(employee_distances, key=employee_distances.get)
        best_distance = employee_distances[best_emp]
        
        # Convert distance to confidence (inverse relationship)
        # Using a sigmoid-like mapping
        max_distance = max(employee_distances.values())
        if max_distance > 0:
            normalized_distance = best_distance / max_distance
            confidence = 1.0 / (1.0 + np.exp(5 * (normalized_distance - 0.5)))
        else:
            confidence = 1.0
        
        # Apply threshold - only return match if confident enough
        if confidence >= CONFIDENCE_THRESHOLD:
            # Quantize confidence to prevent information leakage
            # Only report categorical confidence levels
            if confidence >= 0.95:
                confidence_level = "very_high"
            elif confidence >= 0.85:
                confidence_level = "high"
            elif confidence >= CONFIDENCE_THRESHOLD:
                confidence_level = "moderate"
            else:
                confidence_level = "low"
            
            return {
                "match_found": True,
                "employee_id": best_emp,
                "confidence_level": confidence_level,
                # Deliberately NOT including:
                # - Exact confidence scores
                # - Scores for other employees
                # - Distance metrics
                # - Probability distributions
            }
        else:
            return {
                "match_found": False,
                "message": "No confident match found"
                # Deliberately NOT revealing how close the best match was
            }


