def require_auth(allowed_roles=None):
    """Authentication decorator."""
    if allowed_roles is None:
        allowed_roles = ['admin', 'security', 'reader']
    
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            auth_header = request.headers.get('Authorization', '')
            if not auth_header.startswith('Bearer '):
                return jsonify({"error": "Authentication required"}), 401
            
            token = auth_header[7:]  # Remove 'Bearer '
            
            # Validate token length to prevent DoS
            if len(token) > 256:
                return jsonify({"error": "Invalid token"}), 401
            
            is_valid, role = token_store.validate_token(token)
            if not is_valid:
                logger.info("Failed authentication attempt")
                return jsonify({"error": "Invalid or expired token"}), 401
            
            if role not in allowed_roles:
                logger.info(f"Unauthorized role attempt: {role}")
                return jsonify({"error": "Insufficient permissions"}), 403
            
            g.auth_role = role
            return f(*args, **kwargs)
        return decorated_function
    return decorator


def require_rate_limit(f):
    """Rate limiting decorator."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Use IP + auth token hash as client identifier
        client_ip = request.remote_addr or 'unknown'
        auth = request.headers.get('Authorization', '')
        client_id = hashlib.sha256(f"{client_ip}:{auth}".encode()).hexdigest()[:16]
        
        if not rate_limiter.is_allowed(client_id):
            logger.warning(f"Rate limit exceeded for client")
            return jsonify({"error": "Rate limit exceeded. Try again later."}), 429
        
        return f(*args, **kwargs)
    return decorated_function


def validate_image(file_storage) -> Image.Image:
    """Securely validate and load an uploaded image."""
    if not file_storage or not file_storage.filename:
        raise ValueError("No file provided")
    
    # Check filename extension
    filename = secure_filename(file_storage.filename)
    ext = filename.rsplit('.', 1)[-1].lower() if '.' in filename else ''
    if ext not in ALLOWED_EXTENSIONS:
        raise ValueError(f"File type not allowed. Allowed: {ALLOWED_EXTENSIONS}")
    
    # Read with size limit
    file_storage.seek(0, 2)  # Seek to end
    size = file_storage.tell()
    file_storage.seek(0)  # Seek back to start
    
    if size > MAX_IMAGE_SIZE:
        raise ValueError(f"File too large. Maximum size: {MAX_IMAGE_SIZE} bytes")
    
    if size == 0:
        raise ValueError("Empty file")
    
    # Read raw bytes
    raw_bytes = file_storage.read(MAX_IMAGE_SIZE + 1)
    if len(raw_bytes) > MAX_IMAGE_SIZE:
        raise ValueError("File too large")
    
    # Validate it's actually an image using PIL
    try:
        img = Image.open(io.BytesIO(raw_bytes))
        img.verify()  # Verify it's a valid image
        # Re-open after verify (verify can close the image)
        img = Image.open(io.BytesIO(raw_bytes))
        # Force load to catch decompression bombs
        img.load()
    except Exception as e:
        raise ValueError("Invalid or corrupted image file")
    
    # Check image dimensions (prevent decompression bombs)
    max_dimension = 4096
    if img.width > max_dimension or img.height > max_dimension:
        raise ValueError(f"Image dimensions too large. Maximum: {max_dimension}x{max_dimension}")
    
    # Check pixel count
    if img.width * img.height > 16_000_000:  # 16 megapixels
        raise ValueError("Image has too many pixels")
    
    return img


def validate_employee_id(emp_id: str) -> str:
    """Validate and sanitize employee ID."""
    if not isinstance(emp_id, str):
        raise ValueError("Employee ID must be a string")
    if len(emp_id) == 0 or len(emp_id) > 100:
        raise ValueError("Employee ID must be 1-100 characters")
    # Allowlist: alphanumeric, hyphens, underscores
    sanitized = ''.join(c for c in emp_id if c.isalnum() or c in '-_')
    if sanitized != emp_id:
        raise ValueError("Employee ID contains invalid characters. Use alphanumeric, hyphens, underscores only.")
    return sanitized


