@app.route('/api/v1/train', methods=['POST'])
@require_rate_limit
@require_auth(allowed_roles=['admin'])
def train_model():
    """
    Train the model on uploaded employee photos.
    
    Expects multipart form data with:
    - Multiple files named as 'employee_id__filename.jpg'
      (employee ID separated by double underscore from filename)
    
    Or JSON body with:
    - training_dir: path to pre-validated training directory on server
    """
    try:
        training_data = {}
        
        # Option 1: Upload files directly
        if request.files:
            for key, file_storage in request.files.items(multi=True):
                # Extract employee ID from the form field name
                if '__' not in key:
                    return jsonify({
                        "error": "File field names must be 'employeeId__filename'"
                    }), 400
                
                emp_id = key.split('__')[0]
                emp_id = validate_employee_id(emp_id)
                
                img = validate_image(file_storage)
                
                if emp_id not in training_data:
                    training_data[emp_id] = []
                training_data[emp_id].append(img)
        
        # Option 2: Use pre-staged training directory on server
        elif request.is_json:
            data = request.get_json(silent=True)
            if not data:
                return jsonify({"error": "No data provided"}), 400
            
            # Only allow the pre-configured training directory
            # Do NOT allow arbitrary paths (path traversal prevention)
            use_default = data.get('use_default_directory', False)
            if not use_default:
                return jsonify({
                    "error": "Only the default training directory is allowed"
                }), 400
            
            training_dir = Path(TRAINING_DATA_DIR).resolve()
            
            # Verify the path is within expected bounds
            allowed_base = Path(TRAINING_DATA_DIR).resolve()
            if not str(training_dir).startswith(str(allowed_base)):
                return jsonify({"error": "Invalid training directory"}), 400
            
            if not training_dir.is_dir():
                return jsonify({"error": "Training directory not found"}), 404
            
            # Each subdirectory is an employee
            for emp_dir in sorted(training_dir.iterdir()):
                if not emp_dir.is_dir():
                    continue
                
                emp_id = validate_employee_id(emp_dir.name)
                training_data[emp_id] = []
                
                for img_path in sorted(emp_dir.iterdir()):
                    if img_path.suffix.lower().lstrip('.') not in ALLOWED_EXTENSIONS:
                        continue
                    
                    # Verify no symlink traversal
                    resolved = img_path.resolve()
                    if not str(resolved).startswith(str(allowed_base)):
                        logger.warning(f"Skipping suspicious path: {img_path}")
                        continue
                    
                    file_size = img_path.stat().st_size
                    if file_size > MAX_IMAGE_SIZE or file_size == 0:
                        continue
                    
                    try:
                        img = Image.open(img_path)
                        img.verify()
                        img = Image.open(img_path)
                        img.load()
                        
                        if img.width > 4096 or img.height > 4096:
                            continue
                        
                        training_data[emp_id].append(img)
                    except Exception:
                        logger.warning(f"Skipping invalid image in training data")
                        continue
        else:
            return jsonify({"error": "No training data provided"}), 400
        
        if not training_data:
            return jsonify({"error": "No valid training data found"}), 400
        
        total_images = sum(len(imgs) for imgs in training_data.values())
        if total_images < 2:
            return jsonify({"error": "Need at least 2 training images"}), 400
        
        # Train the model
        model.train(training_data)
        
        logger.info(f"Model trained: {len(training_data)} employees, {total_images} images")
        
        return jsonify({
            "status": "success",
            "employees_registered": len(training_data),
            "total_training_images": total_images
        })
    
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.error(f"Training error: {type(e).__name__}")
        return jsonify({"error": "Internal training error"}), 500


@app.route('/api/v1/identify', methods=['POST'])
@require_rate_limit
@require_auth(allowed_roles=['admin', 'security'])
def identify_face():
    """
    Identify a face in an uploaded image.
    
    SECURITY NOTE: This endpoint deliberately returns ONLY the top match
    with a categorical confidence level. It does NOT return:
    - Exact confidence scores (prevents gradient-based model inversion)
    - Scores for other employees (prevents enumeration)
    - Distance metrics (prevents reconstruction attacks)
    - Full probability distributions (prevents membership inference)
    
    This design prevents model inversion attacks where an adversary
    iteratively queries the API to reconstruct training images or
    determine if specific individuals are in the training set.
    """
    if not model.is_trained:
        return jsonify({"error": "Model not trained yet"}), 503
    
    try:
        if 'image' not in request.files:
            return jsonify({"error": "No image file provided. Use 'image' field."}), 400
        
        img = validate_image(request.files['image'])
        
        # Get secure prediction (only top match, categorical confidence)
        result = model.predict_secure(img)
        
        # Add metadata
        result["timestamp"] = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
        
        # Log access (without sensitive details)
        if result.get("match_found"):
            logger.info("Face identification: match found")
        else:
            logger.info("Face identification: no match")
        
        return jsonify(result)
    
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except RuntimeError as e:
        return jsonify({"error": str(e)}), 503
    except Exception as e:
        logger.error(f"Identification error: {type(e).__name__}")
        return jsonify({"error": "Internal error during identification"}), 500


