    token = token_store.generate_token(role)
    
    logger.info(f"New token generated for role: {role}")
    
    # This is the ONLY time the plaintext token is available
    return jsonify({
        "token": token,
        "role": role,
        "warning": "Store this token securely. It cannot be retrieved again."
    })


